var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`LELOUCH_GEASS_NULL_NULL`,text:{KOREA:`역시 당신이 이곳의 사장이었나.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LELOUCH_GEASS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`LELOUCH_GEASS_NULL_NULL`,text:{KOREA:`하지만 의문이군. 내게 모습을 드러낸 다는 것이 어떤 의미인 줄은 이해하고 있을 텐데?`},stage:{bg:`BLACK`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LELOUCH_GEASS_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LELOUCH_GEASS_NULL_NULL`,text:{KOREA:`…….`},stage:{bg:`BLACK`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LELOUCH_GEASS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`LELOUCH_GEASS_NULL_NULL`,text:{KOREA:`훗, 농담이야. 신세를 진 사람에게 함부로 기아스를 걸지는 않아.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LELOUCH_GEASS_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`LELOUCH_GEASS_NULL_NULL`,text:{KOREA:`이 힘은 브리타니아를 부수기 위한 무기. 그리고 무기의 사용은 언제나 신중해야 하지.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LELOUCH_GEASS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`LELOUCH_GEASS_NULL_NULL`,text:{KOREA:`무엇보다도 지금까지 지켜봐 온 당신이라면…… 그리 쉽게 기아스에 당해줄 것 같지는 않거든.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LELOUCH_GEASS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`LELOUCH_GEASS_NULL_NULL`,text:{KOREA:`그래서 하고 싶은 말은 뭐지?`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LELOUCH_GEASS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`LELOUCH_GEASS_NULL_NULL`,text:{KOREA:`…….`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LELOUCH_GEASS_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`LELOUCH_GEASS_NULL_NULL`,text:{KOREA:`종신 계약? 하하, 말도 안 되는 소리를.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LELOUCH_GEASS_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`LELOUCH_GEASS_NULL_NULL`,text:{KOREA:`미안하지만 나는 어떤 마녀와 이미 계약을 해버려서 말이야. 필요 이상으로 계약을 늘리고 싶지는 않아.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LELOUCH_GEASS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`LELOUCH_GEASS_NULL_NULL`,text:{KOREA:`뭐…… 그 대신, 이곳에서 신세를 지는 동안에는 잠시 당신에게 힘을 빌려주지.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LELOUCH_GEASS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`LELOUCH_GEASS_NULL_NULL`,text:{KOREA:`당신에게도 이런 저런 사정이 있는 것 같으니까 말이야.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LELOUCH_GEASS_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};